SELECT sn.*, u.username, u.real_name
FROM sys_notice sn
         LEFT JOIN sys_user u ON sn.receive_user_id = u.user_id
WHERE sn.receive_user_id = #{receiveUserId}
ORDER BY sn.create_time DESC
    LIMIT #{limit} OFFSET #{offset}

